!function(){"use strict";window.AMH&&AMH.register?AMH.register("nav-ctafooter",function(a){AMH.injectCSS("nav-ctafooter",".amh-navcta{text-align:center;padding-top:4rem;padding-bottom:3rem;background:var(--amh-bg-surface,#0a0a0a);border:1px solid var(--amh-border-subtle,rgba(242,242,242,0.08));border-radius:var(--amh-radius-md,0.5rem)}.amh-navcta_link{text-decoration:none;display:inline-block;cursor:pointer;font-size:clamp(2.5rem,8vw,5rem);font-weight:500;line-height:1.1;color:var(--amh-text-primary,#F2F2F2)}.amh-navcta-char{display:inline-block;transition:color .3s var(--expo-out),transform .3s var(--spring-active);transition-delay:calc(var(--char-index,0) * 25ms)}.amh-navcta_link:hover .amh-navcta-char{color:var(--amh-text-accent,#00B6B6);transform:translateY(-4px)}.amh-navcta_sub{font-size:.875rem;color:var(--amh-text-muted,#999);margin-top:1.5rem}.amh-navcta_footer{display:flex;justify-content:space-between;align-items:center;margin-top:3rem;padding-top:1.5rem;border-top:1px solid var(--amh-border-subtle,rgba(242,242,242,0.08))}.amh-navcta_copy{font-size:.6875rem;color:var(--amh-text-muted,#666)}.amh-navcta_socials{display:flex;gap:1.25rem}.amh-navcta_social{font-size:.75rem;color:var(--amh-text-muted,#999);text-decoration:none;transition:color .3s var(--expo-out)}.amh-navcta_social:hover{color:var(--amh-text-accent,#00B6B6)}@media(prefers-reduced-motion:reduce){.amh-navcta-char{transition:none!important}}@media(max-width:479px){.amh-navcta_footer{flex-direction:column;gap:.75rem;text-align:center}}");var t=a.querySelector(".amh-navcta_link");if(t&&!t.querySelector(".amh-navcta-char")){var r=t.textContent.trim();r&&(t.innerHTML=r.split("").map(function(a,t){return" "===a?'<span class="amh-navcta-char" style="--char-index:'+t+'">&nbsp;</span>':'<span class="amh-navcta-char" style="--char-index:'+t+'">'+a+"</span>"}).join(""))}}):console.warn("amh-nav-ctafooter: amh-core.js must be loaded first.")}();